var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"꼬마야, 조심해!","JPN":"お嬢ちゃん、気を付けろ！","ENG":"Watch out, kid!","TWN":"小傢伙，小心！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"고마워요!","JPN":"ありがとうございます！","ENG":"Thanks!","TWN":"謝謝！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그리고 대장님도요! 하앗!","JPN":"隊長さんも気を付けてくださいね！　はっ！","ENG":"You too, Captain! Hiyah!","TWN":"隊長也是哦！哈啊！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"휴우, 카운터가 같이 싸워 주니까 든든하네.","JPN":"ふう、カウンターが一緒に戦ってくれるから心強いな。","ENG":"Phew, it sure is reassuring to have a Counter backing us up.","TWN":"呼，跟制裁者一起打仗還真踏實。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 칭찬 받았다. 리타 언니는 제가 맨날 걸리적거린다고 싫어하거든요.","JPN":"へへっ、褒められちゃった。リタお姉ちゃんはいつも私のことを邪魔くさいって嫌がるんです。","ENG":"Heh heh, thanks for the compliment! Rita always says I just get in her way.","TWN":"嘿嘿，被誇獎嘍。麗塔姐姐之前還嫌棄我每天都扯後腿呢。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"뭐? 자기는 이럴 때 코빼기도 안 비치면서?","JPN":"は？　自分はこんな時に顔も出さないくせに？","ENG":"What? But she hasn't even showed her face in this crisis!","TWN":"什麼？這種情況連個影子都沒看到的人，還好意思說你？"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니는 싸우는 걸 별로 안 좋아하거든요.","JPN":"リタお姉ちゃんは戦いがあまり好きじゃないんです。","ENG":"She's not a big fan of fighting.","TWN":"姐姐不怎麼喜歡打架。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님 말로는 남들보다 CRF 소비가 많대요.","JPN":"代表の話だと、他の人よりCRFの消費が多いらしくて。","ENG":"The boss says she spends more CRF than others.","TWN":"按我們家BOSS的話來說… 就是她會消耗比別人更多的CRF。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"흐음...... 난 카운터가 아니라 잘 모르겠지만 그건 핑계 같은데......","JPN":"ふむ……俺はカウンターじゃないからよくわからんが、ただの言い訳に聞こえるな……","ENG":"Hmm... I'm not a Counter, so I wouldn't know any better... but that just sounds like a lame excuse.","TWN":"唔……你說的這個因為我不是制裁者也不是很懂，不過還是像藉口……"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"11시 방향! 놈들이 또 떼거지로 몰려온다!","JPN":"11時方向！　敵の群れが押し寄せてくるぞ！","ENG":"11 o'clock! Another wave incoming!","TWN":"11點方向！那些傢伙又衝過來了！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"제길, 총알이 다 떨어졌어! 누가 좀 나눠 줘!","JPN":"くそっ、弾切れだ！　誰か分けてくれ！","ENG":"Darn it, I'm all out of ammo! Somebody hook me up!","TWN":"該死，沒子彈了！誰分給我一點！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"이런, 아직 끝이 아니었나!","JPN":"しまった、まだ終わりじゃねえのか！","ENG":"Oh gosh, it's not over yet?","TWN":"真是的，沒完沒了！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"엄호해 주세요! 저도 다른 분들을 지켜 드릴게요!","JPN":"援護お願いします！　私も他の方を守ります！","ENG":"Cover me! I'll keep the others safe!","TWN":"掩護我！我還要保護其他人！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"어? 저건......?","JPN":"あれ？　あれは……？","ENG":"Huh? Isn't that...","TWN":"額？那是……？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니예요!","JPN":"リタお姉ちゃんです！","ENG":"It's Rita!","TWN":"是麗塔姐姐！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"다행히 늦진 않았군요.","JPN":"間に合ったようですね。","ENG":"Luckily we're not too late.","TWN":"幸好沒有來遲。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 늦었더라도 그리 큰 문제는 없었을 것 같지만.","JPN":"そうだな。間に合わなくても特に問題なかったようだけど。","ENG":"I guess. But it seems like they'd be just fine even if we were late.","TWN":"嗯。即使來晚了也不會有什麼大問題。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 어서 오세요!","JPN":"リタお姉ちゃん！　来てくれたんですね！","ENG":"Rita! It's so good to see you!","TWN":"姐姐！快來！"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"보세요! 언니가 싸우는 동안 다른 아저씨들 안 다치게 잘 지키고 있었어요!","JPN":"見てください！　お姉ちゃんが戦っている間、おじさんたちが怪我しないように守ってあげたんです。","ENG":"Look! I kept everyone safe while you were fighting!","TWN":"看看！姐姐打架的時候我有保護其他叔叔沒讓他們受傷哦！"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"멀미로 다 죽어가던 녀석이 왜 시키지도 않은 짓을 해?","JPN":"ダイブ酔いでまともに動けなかった奴が、なぜ頼んでもいないことをした？","ENG":"I told you to stay put! Aren't you sick from the Dive?","TWN":"你都已經暈船暈的昏天暗地，我有要你這麼做了嗎？"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그, 그치만 다들 싸우는데 구경만 할 수는 없잖아요.","JPN":"で、でもみんな戦っているのにただ見ているわけにはいかないじゃないですか。","ENG":"B-but I couldn't just sit back and watch while everyone was fighting.","TWN":"但、但是大家都在戰鬥，我不能袖手旁觀啊。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여긴 이면세계야. 남 살필 여유 있으면 네 몸이나 잘 챙겨.","JPN":"ここは裏世界だ。他人を気にする余裕があるなら自分のことを考えろ。","ENG":"This is the Counterside. Look after yourself first, if you've got the time then take care of others.","TWN":"這裡是異界。有時間考慮別人，不如先照顧好自己。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"이봐, 사채업자. 칭찬은 못해 줄 망정 너무하잖아.","JPN":"なあ、闇金業者さん。褒めてあげても足りないぐらいなのにひどいんじゃねえか。","ENG":"Hey, loan shark lady. The least you could do is commend the girl.","TWN":"我說，放高利貸的。就算你不誇獎她，也不用這樣說吧。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"이 애 덕분에 부상자가 한 명도 없었어. 대견하지도 않아?","JPN":"この子のおかげで負傷者が一人もいないんだぜ。えらいと思わないか？","ENG":"Thanks to her, nobody got injured. Aren't you proud of her at all?","TWN":"多虧了這個孩子，我們才都毫髮受傷。你不覺得她很了不起嗎？"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 녀석은 제대로 싸울 줄도 모르는 꼬마야.","JPN":"こいつは戦い方もろくに知らないガキだ。","ENG":"She's just a kid who doesn't know how to fight properly.","TWN":"她只是個還不會打架的孩子。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"정상적인 용병이라면 저런 잔챙이들 상대로 어린애 도움 따윈 받지 말았어야지.","JPN":"一人前の傭兵ならあんな雑魚相手に子どもの助けなど要らないだろ。","ENG":"What kind of mercenaries need help from a kid to fend off those small fry?","TWN":"堂堂傭兵不過是對付一些小角色，還需要一個孩子來保護嗎？"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그, 그건......","JPN":"そ、それは……","ENG":"W-well...","TWN":"這、這個……"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"싸우는 폼이 영 어설프던데, 혹시 이전에 다이브 해 본 적은 있나?","JPN":"戦い方が下手なようだが、今までダイブしたことはあるか？","ENG":"You guys didn't seem to know what you were doing. Have you been on a Dive before?","TWN":"我看你們戰鬥的樣子毫無章法，之前有躍入過嗎？"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"......아니. 이번이 처음이야.","JPN":"……いや、今回が初めてだ。","ENG":"No. This is our first time.","TWN":"……沒有，這是第一次。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"하지만 어쩔 수가 없었어!","JPN":"でも仕方なかったんだ！","ENG":"But we had no choice!","TWN":"我們也是逼不得已！"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"댁처럼 카운터면 모를까, 우리 같은 평범한 용병들은 다이브 경력이 없으면 제대로 된 계약조차 해 주지 않는다고.","JPN":"あんたみたいなカウンターと違って俺たちみたいな\\n平凡な傭兵は、ダイブ経歴がないとまともな条件で契約してもらえないんだ。","ENG":"Nobody gives ordinary mercenaries work without prior dive experience. We're not a Counter like you!","TWN":"我們又不是像你一樣的制裁者，像我們這種普通的傭兵如果沒有躍入經驗，根本就不會有人跟我們簽約。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......잘도 여기까지 왔군. 자기 목숨 값을 뭐라고 생각하는 거야?","JPN":"……そんなのでよくここまで来る決心をしたな。自分の命の価値を何だと思ってんだ？","ENG":"Well, you're lucky you made it this far. Is this really worth risking your life though?","TWN":"……真是不把命當一回事，能活到現在也算奇蹟了。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"살아서 돌아가고 싶으면 이제부터라도 똑바로 해.","JPN":"生きて帰りたければ、今からでもしっかり対処しろ。","ENG":"You'd better get your head in the game if you want to make it back alive.","TWN":"如果想活著回去，從現在開始好好做。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대장님......","JPN":"隊長……","ENG":"Captain...","TWN":"隊長……"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"설교는 다 끝났습니까, 휴먼?","JPN":"説教は終わりましたか、ヒューマン？","ENG":"Are you done with your lecture, human?","TWN":"說教結束了嗎，人類？"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 무슨 일인데?","JPN":"ああ。で、なんだ？","ENG":"Just about. What is it?","TWN":"嗯，什麼事？"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"격납고에서 말했다시피, 처음 공격 받은 곳이 불행하게도 함선의 추진부였습니다.","JPN":"格納庫で話したとおり、最初に攻撃を受けた場所は残念ながら艦船の推進機でした。","ENG":"As I mentioned in the hangar, the ship's thrusters were the first to go.","TWN":"正如在機庫中說的那樣，很不幸，第一次被攻擊的地方是艦船推進器的位置。"},"stage":{"bg":"ROOFTOP","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제 계산에 따르면 약 17초 후 함선이 관성을 상실하고 추락할 예정입니다.","JPN":"私の計算によると、約17秒後に艦船が慣性を失い墜落します。","ENG":"According to my calculations, the ship will lose its velocity and crash in approximately 17 seconds.","TWN":"按我的計算，預計大概在17秒後艦船會喪失慣性開始墜落。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"당장 불시착해야 합니다. 죽기 싫으면 난간이든 뭐든 붙잡으십시오.","JPN":"直ちに不時着しなければなりません。死にたくなければ、手すりでも何でも掴まってください。","ENG":"We must prepare for a crash landing immediately. Hang onto anything you can find, if you wish to live.","TWN":"現在要立刻迫降。不想死的，馬上抓住欄杆之類的東西。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......네에?!","JPN":"……ええっ！？","ENG":"Whaaat?","TWN":"……什麼？！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"꺄아아아아아아아아아악!","JPN":"きゃあああああぁぁぁーっ！","ENG":"Eeeeeeek!","TWN":"呃啊啊啊啊啊啊啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};